// ── HELPERS ──────────────────────────────────────────────────────────────────
function parseCode(code) {
  const c = code.toUpperCase().trim();
  const sp = c.match(/^(.+?)\s+([A-Z0-9].*)$/);
  if (sp) return { base: sp[1], variant: sp[2] };
  const at = c.match(/^([A-Z]*\d+)([A-Z]{2,})$/);
  if (at) return { base: at[1], variant: at[2] };
  return { base: c, variant: "" };
}

const STATUS = {
  exists:    { label:"YA EXISTE",              color:"#f87171", bg:"#1e0f0f", border:"#5c1f1f" },
  session:   { label:"REGISTRADO ESTA SESIÓN", color:"#fbbf24", bg:"#1a1400", border:"#54400a" },
  available: { label:"DISPONIBLE",             color:"#4ade80", bg:"#0b1a0f", border:"#1a5c30" },
  partial:   { label:"COINCIDENCIAS",          color:"#94a3b8", bg:"#181818", border:"#2e2e2e" },
};

let sessionGenerated = new Set();

function fmt(n) {
  if (!n) return null;
  return "$" + Number(n).toLocaleString("es-AR");
}

export default function App() {
  const fileInputRef = useRef(null);

  // ── ESTADO MARCA ──────────────────────────────────────────────────────────
  const [allBrands, setAllBrands]     = useState(ALL_BRANDS);
  const [activeBrand, setActiveBrand] = useState("221");
  const [brandSearch, setBrandSearch] = useState("");
  const [loadError, setLoadError]     = useState("");

  const brandData = allBrands[activeBrand] || { codes:[], names:{}, prices:{} };
  const CODES     = brandData.codes;
  const NAMES     = brandData.names;
  const PRICES    = brandData.prices;
  const PREFIX    = activeBrand;
  const codesSet  = useMemo(() => new Set(CODES.map(c => c.toUpperCase().trim())), [CODES]);

  const isAvailable = useCallback((code) => {
    const u = code.toUpperCase().trim();
    return !codesSet.has(u) && !sessionGenerated.has(u);
  }, [codesSet]);

  const checkCode = useCallback((code) => {
    const u = code.toUpperCase().trim();
    if (codesSet.has(u)) return "exists";
    if (sessionGenerated.has(u)) return "session";
    return "available";
  }, [codesSet]);

  const getName  = useCallback((c) => NAMES[c.toUpperCase().trim()] || null, [NAMES]);
  const getPrice = useCallback((c) => PRICES[c.toUpperCase().trim()] || null, [PRICES]);

  const generateAlts = useCallback((code) => {
    const c = code.toUpperCase().trim();
    const results = [];
    const groups = [];
    let m; const rx = /(\d+)/g;
    while ((m = rx.exec(c)) !== null)
      groups.push({ value: parseInt(m[1]), index: m.index, raw: m[1] });
    if (!groups.length) return { results:[], siblings:[] };
    const tried = new Set();
    for (let g = groups.length-1; g >= 0; g--) {
      const grp = groups[g]; let found = 0;
      for (let d = 1; d <= 50 && found < 3; d++) {
        const n = grp.value + d;
        const padded = grp.raw.startsWith("0") && grp.raw.length > 1
          ? String(n).padStart(grp.raw.length,"0") : String(n);
        const cand = c.slice(0,grp.index) + padded + c.slice(grp.index+grp.raw.length);
        if (!tried.has(cand) && isAvailable(cand)) {
          tried.add(cand);
          results.push({ code: cand });
          found++;
        }
      }
      if (results.length >= 6) break;
    }
    const { base } = parseCode(c);
    const siblings = CODES.filter(ec => parseCode(ec).base === base && ec.toUpperCase() !== c).slice(0,8);
    return { results: results.slice(0,6), siblings };
  }, [CODES, isAvailable]);

  // ── CARGAR EXCEL ──────────────────────────────────────────────────────────
  const handleFileLoad = async (file) => {
    if (!file) return;
    setLoadError("");
    try {
      const buf = await file.arrayBuffer();
      const data = new Uint8Array(buf);

      // Extract strings via heuristic scan (same method used to build ALL_BRANDS)
      const sst = [];
      for (let i = 0; i < data.length - 10; i++) {
        const length = data[i] | (data[i+1] << 8);
        const flag   = data[i+2];
        if (length >= 2 && length <= 120 && flag === 0x00) {
          let ok = true;
          for (let j = 0; j < length; j++) {
            const b = data[i+3+j];
            if (b < 0x20 || b > 0x7e) { ok = false; break; }
          }
          if (ok) {
            const text = String.fromCharCode(...data.slice(i+3, i+3+length)).trim();
            if (text) sst.push(text);
          }
        }
      }

      // Raw scan LABELSST (0xFD 0x00, len=10) — captura TODAS las hojas
      const labels = {};
      const prices = {};
      for (let i = 0; i < data.length - 14; i++) {
        if (data[i] === 0xFD && data[i+1] === 0x00) {
          const rlen = data[i+2] | (data[i+3] << 8);
          if (rlen === 10) {
            const row = data[i+4] | (data[i+5] << 8);
            const col = data[i+6] | (data[i+7] << 8);
            const idx = data[i+10] | (data[i+11]<<8) | (data[i+12]<<16) | (data[i+13]<<24);
            if (idx < sst.length) {
              if (!labels[row]) labels[row] = {};
              if (labels[row][col] === undefined) labels[row][col] = sst[idx];
            }
          }
        }
        if (data[i] === 0x7E && data[i+1] === 0x02) {
          const rlen = data[i+2] | (data[i+3] << 8);
          if (rlen === 10) {
            const row = data[i+4] | (data[i+5] << 8);
            const col = data[i+6] | (data[i+7] << 8);
            if (col === 2 && prices[row] === undefined) {
              let rk = (data[i+10] | (data[i+11]<<8) | (data[i+12]<<16) | (data[i+13]<<24)) | 0;
              let val;
              if (rk & 2) { val = rk >> 2; }
              else {
                const b8 = new ArrayBuffer(8); const dv = new DataView(b8);
                dv.setUint32(4, (rk & ~3) >>> 0, true);
                val = dv.getFloat64(0, true);
              }
              if (rk & 1) val /= 100;
              if (val > 500) prices[row] = Math.round(val);
            }
          }
        }
      }

      // Build brands — handles the 2-column Excel layout correctly
      const newBrands = {};
      const seen = new Set();
      const isCode = (s) => /^\d{3}-/.test(s);
      let pendingName = null; // { code, price } waiting for name from next N+C row

      const addProduct = (fullCode, name, p) => {
        if (seen.has(fullCode)) return;
        if (!/^\d{3}-/.test(fullCode)) return;
        seen.add(fullCode);
        const brand = fullCode.slice(0,3);
        const code  = fullCode.slice(4);
        if (!code) return;
        if (!newBrands[brand]) newBrands[brand] = { codes:[], names:{}, prices:{} };
        newBrands[brand].codes.push(code);
        if (name) newBrands[brand].names[code] = name;
        if (p && p > 500) newBrands[brand].prices[code] = Math.round(p);
      };

      for (const row of Object.keys(labels).map(Number).sort((a,b)=>a-b)) {
        const c0 = (labels[row][0] || "").trim().toUpperCase();
        const c1 = (labels[row][1] || "").trim().toUpperCase();
        const price = prices[row] || null;
        const b0 = isCode(c0), b1 = isCode(c1);

        if (b0 && b1) {
          // Both codes: col0 deferred for name, col1 added with same price
          if (pendingName) { addProduct(pendingName.code, "", pendingName.price); }
          pendingName = { code: c0, price };
          addProduct(c1, "", price);
        } else if (b0 && !b1) {
          // col0=code, col1=name
          if (pendingName) { addProduct(pendingName.code, "", pendingName.price); pendingName = null; }
          addProduct(c0, c1.length > 3 ? c1 : "", price);
        } else if (!b0 && b1) {
          // col0=name, col1=code
          if (pendingName) {
            addProduct(pendingName.code, c0.length > 3 ? c0 : "", pendingName.price);
            pendingName = null;
            addProduct(c1, "", price);
          } else {
            addProduct(c1, c0.length > 3 ? c0 : "", price);
          }
        }
      }
      if (pendingName) addProduct(pendingName.code, "", pendingName.price);

      const total = Object.values(newBrands).reduce((s,b) => s+b.codes.length, 0);
      if (total === 0) throw new Error("No se encontraron códigos con formato NNN-CODIGO");

      sessionGenerated = new Set();
      setAllBrands(newBrands);
      const def = newBrands["221"] ? "221" : Object.keys(newBrands)[0];
      setActiveBrand(def);
      setNewCodes([]);
      showToast(`✓ ${total.toLocaleString()} productos · ${Object.keys(newBrands).length} marcas cargadas`);
    } catch(e) {
      setLoadError(e.message || "Error al leer el archivo");
    }
  };

  // ── UI STATE ──────────────────────────────────────────────────────────────
  const [tab, setTab]                   = useState("check");
  const [mode, setMode]                 = useState("verify");
  const [inputCode, setInputCode]       = useState("");
  const [checkResult, setCheckResult]   = useState(null);
  const [alternatives, setAlternatives] = useState(null);
  const [newCodes, setNewCodes]         = useState([]);
  const [toast, setToast]               = useState(null);
  const [nameQuery, setNameQuery]       = useState("");
  const [nameMatches, setNameMatches]   = useState(null);
  const [selectedFamily, setSelectedFamily] = useState(null);
  const [colorSuffix, setColorSuffix]   = useState("");
  const [genStep, setGenStep]           = useState(1);
  const [genResult, setGenResult]       = useState(null);
  const [searchTerm, setSearchTerm]     = useState("");
  const [brandSearch2, setBrandSearch2] = useState(brandSearch);

  const showToast = (msg) => { setToast(msg); setTimeout(() => setToast(null), 2600); };
  const resetAll  = () => {
    setCheckResult(null); setAlternatives(null); setGenResult(null);
    setInputCode(""); setNameQuery(""); setNameMatches(null);
    setSelectedFamily(null); setColorSuffix(""); setGenStep(1);
  };

  // ── CHECK ─────────────────────────────────────────────────────────────────
  const handleCheck = () => {
    const input = inputCode.trim().toUpperCase();
    if (!input) return;
    const st = checkCode(input);
    if (st !== "available") {
      setCheckResult({ code:input, status:st, matches:null });
      setAlternatives(generateAlts(input));
    } else {
      const matches = CODES.filter(c => c.toUpperCase().includes(input));
      if (matches.length > 0 && matches.length < CODES.length) {
        setCheckResult({ code:input, status:"partial", matches });
      } else {
        setCheckResult({ code:input, status:"available", matches:null });
      }
      setAlternatives(null);
    }
  };

  const handleRegister = (code) => {
    const u = code.toUpperCase().trim();
    sessionGenerated.add(u);
    setNewCodes(prev => [...prev, { code:u, full:`${PREFIX}-${u}` }]);
    showToast(`✓ Registrado: ${PREFIX}-${u}`);
    setCheckResult(null); setAlternatives(null); setInputCode("");
  };

  // ── GENERATE ──────────────────────────────────────────────────────────────
  const searchByName = () => {
    const q = nameQuery.trim().toUpperCase();
    if (!q) return;
    const words = q.split(/\s+/).filter(Boolean);
    const scored = Object.entries(NAMES)
      .map(([code, name]) => ({ code, name, score: words.filter(w => name.includes(w)).length }))
      .filter(x => x.score > 0).sort((a,b) => b.score-a.score).slice(0,20);
    setNameMatches(scored);
    setSelectedFamily(null); setColorSuffix(""); setGenStep(2);
  };

  const pickFamily = (code) => {
    const { base } = parseCode(code);
    const siblings = CODES.filter(ec => parseCode(ec).base === base);
    setSelectedFamily({ base, code, siblings });
    setGenStep(3); setGenResult(null); setColorSuffix("");
  };

  const buildAndGenerate = () => {
    if (!selectedFamily) return;
    const suffix = colorSuffix.trim().toUpperCase();
    const base = suffix ? selectedFamily.base + " " + suffix : selectedFamily.base;
    setGenResult({ base, ...generateAlts(base) });
  };

  // ── SEARCH ────────────────────────────────────────────────────────────────
  const filteredCodes = useMemo(() => {
    if (!searchTerm) return CODES.slice(0,80);
    const q = searchTerm.toLowerCase();
    return CODES.filter(c => c.toLowerCase().includes(q) || (NAMES[c]||"").toLowerCase().includes(q));
  }, [searchTerm, CODES, NAMES]);

  // ── BRANDS ────────────────────────────────────────────────────────────────
  const allBrandsSorted = useMemo(() =>
    Object.entries(allBrands).sort((a,b) => b[1].codes.length - a[1].codes.length),
  [allBrands]);

  const filteredBrands = useMemo(() => {
    const q = brandSearch.trim();
    if (!q) return allBrandsSorted;
    return allBrandsSorted.filter(([p]) => p.includes(q));
  }, [brandSearch, allBrandsSorted]);

  const totalProducts = useMemo(() =>
    Object.values(allBrands).reduce((s,b) => s+b.codes.length, 0), [allBrands]);

  // ── STYLES ────────────────────────────────────────────────────────────────
  const S = {
    card:    { background:"#1a1a1a", border:"1px solid #2a2a2a", borderRadius:10, padding:20, marginBottom:14 },
    label:   { fontSize:10, letterSpacing:3, color:"#888", marginBottom:7, display:"block" },
    input:   { width:"100%", background:"#111", border:"1px solid #333", borderRadius:7,
               padding:"10px 12px", color:"#e8e8e8", fontSize:13, outline:"none",
               boxSizing:"border-box", fontFamily:"'Inter',sans-serif" },
    btn:     { padding:"10px 20px", background:"#e8e8e8", color:"#111", border:"none",
               borderRadius:7, cursor:"pointer", fontSize:12, fontWeight:700,
               fontFamily:"'Inter',sans-serif" },
    ghost:   { padding:"8px 14px", background:"transparent", color:"#666",
               border:"1px solid #2a2a2a", borderRadius:7, cursor:"pointer",
               fontSize:11, fontFamily:"'Inter',sans-serif" },
  };

  const hl = (text, q) => {
    if (!q || !text) return text;
    const safe = q.replace(/[.*+?^${}()|[\]\\]/g,"\\$&");
    const parts = text.split(new RegExp(`(${safe})`, "gi"));
    return parts.map((p,i) => i%2===1
      ? <span key={i} style={{ background:"#facc15", color:"#111", fontWeight:700, borderRadius:2, padding:"0 1px" }}>{p}</span>
      : p);
  };

  // ── RENDER ────────────────────────────────────────────────────────────────
  return (
    <div style={{ minHeight:"100vh", background:"#111111", color:"#e8e8e8", fontFamily:"'Inter',sans-serif" }}>

      {/* ── HEADER ── */}
      <div style={{ background:"#141414", borderBottom:"1px solid #2a2a2a", padding:"20px 28px 0" }}>
        <div style={{ maxWidth:880, margin:"0 auto" }}>
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:2 }}>
            <div>
              <div style={{ fontSize:10, letterSpacing:4, color:"#444" }}>SISTEMA DE GESTIÓN · PREFIJO {PREFIX}</div>
              <div style={{ display:"flex", alignItems:"baseline", gap:10, margin:"4px 0" }}>
                <h1 style={{ fontSize:21, fontWeight:700, margin:0, color:"#fff" }}>Generador de Códigos</h1>
                <span style={{ fontSize:21, fontWeight:700, color:"#bbb" }}>{PREFIX}</span>
              </div>
              <div style={{ fontSize:11, color:"#555", marginBottom:16 }}>
                {CODES.length.toLocaleString()} artículos · marca {PREFIX} · {newCodes.length} nuevos esta sesión ·{" "}
                <span style={{ color:"#444" }}>{Object.keys(allBrands).length} marcas · {totalProducts.toLocaleString()} productos total</span>
              </div>
            </div>
            {/* Botón cargar Excel */}
            <div style={{ display:"flex", flexDirection:"column", alignItems:"flex-end", gap:4, marginTop:4 }}>
              <button onClick={() => fileInputRef.current?.click()}
                style={{ ...S.ghost, display:"flex", alignItems:"center", gap:6 }}>
                📂 Actualizar Excel
              </button>
              <input ref={fileInputRef} type="file" accept=".xls,.xlsx"
                style={{ display:"none" }}
                onChange={e => handleFileLoad(e.target.files[0])} />
              {loadError && <div style={{ fontSize:10, color:"#f87171", maxWidth:180, textAlign:"right" }}>{loadError}</div>}
            </div>
          </div>

          {/* Tabs */}
          <div style={{ display:"flex" }}>
            {[
              { id:"check",  label:"Verificar / Crear" },
              { id:"search", label:"Buscar artículos" },
              { id:"brands", label:`Marcas (${Object.keys(allBrands).length})` },
              { id:"list",   label:`Sesión (${newCodes.length})` },
            ].map(t => (
              <button key={t.id} onClick={() => setTab(t.id)} style={{
                padding:"8px 18px", background: tab===t.id ? "#e8e8e8" : "transparent",
                color: tab===t.id ? "#111" : "#555", border:"none",
                borderBottom: tab===t.id ? "2px solid #e8e8e8" : "2px solid transparent",
                cursor:"pointer", fontSize:12, fontFamily:"'Inter',sans-serif",
                borderRadius: tab===t.id ? "4px 4px 0 0" : 0, transition:"all .15s",
              }}>{t.label}</button>
            ))}
          </div>
        </div>
      </div>

      <div style={{ maxWidth:880, margin:"0 auto", padding:"24px 28px" }}>

        {/* ── VERIFICAR / CREAR ── */}
        {tab === "check" && (<>
          <div style={{ display:"flex", gap:6, marginBottom:14 }}>
            {[["verify","🔍 Verificar código"],["generate","✨ Generar código nuevo"]].map(([m,lbl]) => (
              <button key={m} onClick={() => { setMode(m); resetAll(); }}
                style={{ padding:"8px 18px",
                  background: mode===m ? "#e8e8e8" : "#1a1a1a",
                  color: mode===m ? "#111" : "#666",
                  border:`1px solid ${mode===m ? "#e8e8e8" : "#2a2a2a"}`,
                  borderRadius:8, cursor:"pointer", fontSize:12,
                  fontFamily:"'Inter',sans-serif", fontWeight: mode===m ? 700 : 400 }}>
                {lbl}
              </button>
            ))}
          </div>

          {/* VERIFY */}
          {mode === "verify" && (
          <div style={S.card}>
            <span style={S.label}>CÓDIGO DEL ARTÍCULO (sin "{PREFIX}-")</span>
            <div style={{ display:"flex", gap:8 }}>
              <div style={{ background:"#111", border:"1px solid #2a2a2a", borderRadius:7,
                padding:"10px 12px", color:"#555", fontSize:14, display:"flex",
                alignItems:"center", whiteSpace:"nowrap" }}>{PREFIX}-</div>
              <input value={inputCode} onChange={e => setInputCode(e.target.value)}
                onKeyDown={e => e.key==="Enter" && handleCheck()}
                placeholder="Ej: M1103C NGR" autoFocus style={S.input} />
              <button onClick={handleCheck} style={S.btn}>Verificar</button>
            </div>
          </div>)}

          {/* RESULT */}
          {checkResult && (() => {
            const st = STATUS[checkResult.status];
            return (
              <div style={{ background:st.bg, border:`1px solid ${st.border}`, borderRadius:10, padding:20, marginBottom:14 }}>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", flexWrap:"wrap", gap:10 }}>
                  <div>
                    <div style={{ fontWeight:700, fontSize:18, color:"#e8e8e8", fontFamily:"monospace", marginBottom:4 }}>
                      {PREFIX}-{checkResult.code}
                    </div>
                    {getName(checkResult.code) && (
                      <div style={{ fontSize:12, color:"#aaa", marginBottom:2 }}>📦 {getName(checkResult.code)}</div>
                    )}
                    {getPrice(checkResult.code) && (
                      <div style={{ fontSize:12, color:"#888" }}>
                        💲 Lista: <span style={{ color:"#e8e8e8", fontWeight:600 }}>{fmt(getPrice(checkResult.code))}</span>
                      </div>
                    )}
                  </div>
                  <span style={{ fontSize:10, letterSpacing:3, fontWeight:700, color:st.color,
                    border:`1px solid ${st.border}`, padding:"4px 10px", borderRadius:4, whiteSpace:"nowrap" }}>
                    {st.label}
                  </span>
                </div>

                {/* Partial matches */}
                {checkResult.status === "partial" && checkResult.matches && (
                  <div style={{ marginTop:14 }}>
                    <div style={{ fontSize:10, letterSpacing:2, color:"#666", marginBottom:8 }}>COINCIDENCIAS</div>
                    <div style={{ display:"flex", flexDirection:"column", gap:5 }}>
                      {checkResult.matches.slice(0,12).map(code => (
                        <div key={code} style={{ background:"#1a1a1a", border:"1px solid #2a2a2a",
                          borderRadius:7, padding:"8px 12px", display:"flex",
                          justifyContent:"space-between", alignItems:"center" }}>
                          <div>
                            <div style={{ fontSize:13, fontWeight:600, color:"#e8e8e8", fontFamily:"monospace" }}>
                              {PREFIX}-{hl(code, checkResult.code)}
                            </div>
                            {getName(code) && <div style={{ fontSize:11, color:"#666", marginTop:2 }}>{getName(code)}</div>}
                          </div>
                          <div style={{ display:"flex", flexDirection:"column", alignItems:"flex-end", gap:3 }}>
                            {getPrice(code) && <span style={{ fontSize:11, color:"#888" }}>{fmt(getPrice(code))}</span>}
                            <span style={{ fontSize:10, color:"#f87171", background:"#1e0f0f",
                              border:"1px solid #5c1f1f", padding:"2px 8px", borderRadius:4 }}>EXISTE</span>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                )}

                {checkResult.status === "available" && (
                  <button onClick={() => handleRegister(checkResult.code)}
                    style={{ ...S.btn, marginTop:14, background:"#4ade80", color:"#0b1a0f" }}>
                    ✓ Registrar {PREFIX}-{checkResult.code} como nuevo
                  </button>
                )}
              </div>
            );
          })()}

          {/* Alternatives */}
          {alternatives && (alternatives.results.length > 0 || alternatives.siblings.length > 0) && (
            <div style={S.card}>
              {alternatives.results.length > 0 && (<>
                <div style={{ fontSize:10, letterSpacing:2, color:"#888", marginBottom:10 }}>CÓDIGOS DISPONIBLES SIMILARES</div>
                <div style={{ display:"flex", flexDirection:"column", gap:6, marginBottom:14 }}>
                  {alternatives.results.map(alt => (
                    <div key={alt.code} style={{ background:"#111", border:"1px solid #2a2a2a",
                      borderRadius:7, padding:"8px 12px",
                      display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                      <span style={{ fontSize:13, fontWeight:600, color:"#4ade80", fontFamily:"monospace" }}>
                        {PREFIX}-{alt.code}
                      </span>
                      <button onClick={() => handleRegister(alt.code)}
                        style={{ ...S.btn, padding:"5px 12px", fontSize:11, background:"#4ade80", color:"#0b1a0f" }}>
                        Registrar
                      </button>
                    </div>
                  ))}
                </div>
              </>)}
              {alternatives.siblings.length > 0 && (<>
                <div style={{ fontSize:10, letterSpacing:2, color:"#666", marginBottom:8 }}>FAMILIA EXISTENTE</div>
                <div style={{ display:"flex", flexWrap:"wrap", gap:6 }}>
                  {alternatives.siblings.map(s => (
                    <span key={s} style={{ background:"#1a1a1a", border:"1px solid #2a2a2a",
                      borderRadius:5, padding:"4px 10px", fontSize:11, color:"#888", fontFamily:"monospace" }}>
                      {PREFIX}-{s}
                    </span>
                  ))}
                </div>
              </>)}
            </div>
          )}

          {/* GENERATE */}
          {mode === "generate" && (<>
            {genStep >= 1 && (
            <div style={S.card}>
              <span style={S.label}>PASO 1 · BUSCAR ARTÍCULO POR NOMBRE</span>
              <div style={{ display:"flex", gap:8 }}>
                <input value={nameQuery} onChange={e => setNameQuery(e.target.value)}
                  onKeyDown={e => e.key==="Enter" && searchByName()}
                  placeholder="Ej: buzo canguro gris" style={S.input} />
                <button onClick={searchByName} style={S.btn}>Buscar</button>
              </div>
            </div>)}

            {genStep >= 2 && nameMatches && (
            <div style={S.card}>
              <span style={S.label}>PASO 2 · SELECCIONÁ EL ARTÍCULO</span>
              {nameMatches.length === 0
                ? <div style={{ color:"#666", fontSize:13 }}>Sin resultados para "{nameQuery}"</div>
                : <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
                  {nameMatches.map(({ code, name }) => (
                    <div key={code} onClick={() => pickFamily(code)}
                      style={{ background: selectedFamily?.code===code ? "#1a2a1a":"#111",
                        border:`1px solid ${selectedFamily?.code===code ? "#1a5c30":"#2a2a2a"}`,
                        borderRadius:7, padding:"10px 14px", cursor:"pointer" }}>
                      <div style={{ fontSize:13, fontWeight:600, color:"#e8e8e8", fontFamily:"monospace" }}>
                        {PREFIX}-{code}
                      </div>
                      <div style={{ display:"flex", gap:14, marginTop:3 }}>
                        <span style={{ fontSize:11, color:"#888" }}>{name}</span>
                        {getPrice(code) && <span style={{ fontSize:11, color:"#666" }}>{fmt(getPrice(code))}</span>}
                      </div>
                    </div>
                  ))}
                </div>
              }
            </div>)}

            {genStep >= 3 && selectedFamily && (
            <div style={S.card}>
              <span style={S.label}>PASO 3 · VARIANTE DE COLOR (opcional)</span>
              <div style={{ fontSize:11, color:"#888", marginBottom:10 }}>
                Familia: <span style={{ color:"#e8e8e8", fontWeight:600 }}>{PREFIX}-{selectedFamily.code}</span>
              </div>
              {selectedFamily.siblings.length > 0 && (
                <div style={{ marginBottom:12 }}>
                  <div style={{ fontSize:10, letterSpacing:2, color:"#555", marginBottom:6 }}>YA EXISTEN EN ESTA FAMILIA</div>
                  <div style={{ display:"flex", flexWrap:"wrap", gap:5 }}>
                    {selectedFamily.siblings.map(s => (
                      <span key={s} style={{ background:"#1a1a1a", border:"1px solid #2a2a2a",
                        borderRadius:5, padding:"3px 9px", fontSize:11, color:"#888", fontFamily:"monospace" }}>
                        {PREFIX}-{s}
                      </span>
                    ))}
                  </div>
                </div>
              )}
              <div style={{ display:"flex", gap:8 }}>
                <input value={colorSuffix} onChange={e => setColorSuffix(e.target.value)}
                  onKeyDown={e => e.key==="Enter" && buildAndGenerate()}
                  placeholder="Ej: ROJO, AZL, NGR… (o dejá vacío)" style={S.input} />
                <button onClick={buildAndGenerate} style={S.btn}>Generar</button>
              </div>
            </div>)}

            {genResult && (
            <div style={{ background: genResult.results.length > 0 ? STATUS.available.bg : STATUS.exists.bg,
              border:`1px solid ${genResult.results.length > 0 ? STATUS.available.border : STATUS.exists.border}`,
              borderRadius:10, padding:20, marginBottom:14 }}>
              <div style={{ fontSize:10, letterSpacing:2, color:"#888", marginBottom:8 }}>CÓDIGO GENERADO</div>
              {genResult.results.length > 0
                ? <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
                  {genResult.results.map(alt => (
                    <div key={alt.code} style={{ background:"#111", border:"1px solid #1a5c30",
                      borderRadius:7, padding:"8px 12px",
                      display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                      <span style={{ fontSize:14, fontWeight:700, color:"#4ade80", fontFamily:"monospace" }}>
                        {PREFIX}-{alt.code}
                      </span>
                      <button onClick={() => handleRegister(alt.code)}
                        style={{ ...S.btn, padding:"5px 12px", fontSize:11, background:"#4ade80", color:"#0b1a0f" }}>
                        Registrar
                      </button>
                    </div>
                  ))}
                </div>
                : <div style={{ color:"#f87171", fontSize:13 }}>No hay códigos disponibles para "{genResult.base}"</div>
              }
            </div>)}
          </>)}
        </>)}

        {/* ── BUSCAR ── */}
        {tab === "search" && (
          <div>
            <div style={S.card}>
              <span style={S.label}>BUSCAR EN MARCA {PREFIX} · {CODES.length.toLocaleString()} artículos</span>
              <input value={searchTerm} onChange={e => setSearchTerm(e.target.value)}
                placeholder="Código o nombre..." autoFocus style={S.input} />
            </div>
            <div style={{ display:"flex", flexDirection:"column", gap:5 }}>
              {filteredCodes.map(code => {
                const name  = getName(code) || "";
                const price = getPrice(code);
                const q     = searchTerm.toLowerCase();
                return (
                  <div key={code} style={{ background:"#1a1a1a", border:"1px solid #2a2a2a",
                    borderRadius:8, padding:"10px 14px",
                    display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                    <div style={{ flex:1, minWidth:0 }}>
                      <div style={{ fontSize:13, fontWeight:600, color:"#e8e8e8", fontFamily:"monospace" }}>
                        {PREFIX}-{hl(code, q)}
                      </div>
                      {name && <div style={{ fontSize:11, color:"#666", marginTop:2 }}>{hl(name, q)}</div>}
                    </div>
                    <div style={{ display:"flex", alignItems:"center", gap:10, marginLeft:12, flexShrink:0 }}>
                      {price && <span style={{ fontSize:12, color:"#888", fontWeight:600 }}>{fmt(price)}</span>}
                      <span style={{ fontSize:10, color:"#f87171", background:"#1e0f0f",
                        border:"1px solid #5c1f1f", padding:"2px 8px", borderRadius:4 }}>EXISTE</span>
                    </div>
                  </div>
                );
              })}
              {filteredCodes.length === 0 && (
                <div style={{ color:"#555", fontSize:13, padding:40, textAlign:"center" }}>
                  Sin resultados para "{searchTerm}"
                </div>
              )}
              {!searchTerm && CODES.length > 80 && (
                <div style={{ color:"#444", fontSize:11, textAlign:"center", padding:10 }}>
                  Mostrando 80 de {CODES.length} — buscá para filtrar
                </div>
              )}
            </div>
          </div>
        )}

        {/* ── MARCAS ── */}
        {tab === "brands" && (
          <div>
            <div style={S.card}>
              <span style={S.label}>{Object.keys(allBrands).length} MARCAS · {totalProducts.toLocaleString()} ARTÍCULOS TOTAL</span>
              <input value={brandSearch} onChange={e => setBrandSearch(e.target.value)}
                placeholder="Filtrar por prefijo (ej: 221)..." autoFocus style={S.input} />
            </div>
            <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill, minmax(160px,1fr))", gap:7 }}>
              {filteredBrands.map(([prefix, d]) => {
                const isActive = prefix === activeBrand;
                return (
                  <div key={prefix}
                    onClick={() => { setActiveBrand(prefix); resetAll(); setTab("check"); }}
                    style={{ background: isActive ? "#1a2a1a" : "#1a1a1a",
                      border:`1px solid ${isActive ? "#1a5c30" : "#2a2a2a"}`,
                      borderRadius:9, padding:"12px 14px", cursor:"pointer", transition:"all .12s" }}>
                    <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:3 }}>
                      <span style={{ fontSize:19, fontWeight:700, fontFamily:"monospace",
                        color: isActive ? "#4ade80" : "#e8e8e8" }}>{prefix}</span>
                      {isActive && (
                        <span style={{ fontSize:9, background:"#0b1a0f", border:"1px solid #1a5c30",
                          color:"#4ade80", borderRadius:3, padding:"1px 5px", letterSpacing:1 }}>ACTIVA</span>
                      )}
                    </div>
                    <div style={{ fontSize:11, color:"#555" }}>{d.codes.length} artículos</div>
                    {Object.keys(d.prices).length > 0 && (
                      <div style={{ fontSize:10, color:"#444", marginTop:1 }}>
                        {Object.keys(d.prices).length} con precio
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* ── SESIÓN ── */}
        {tab === "list" && (
          <div>
            {newCodes.length === 0
              ? <div style={{ color:"#555", fontSize:13, padding:40, textAlign:"center" }}>
                  Todavía no registraste códigos nuevos en esta sesión.
                </div>
              : <>
                <div style={{ fontSize:11, color:"#555", marginBottom:14 }}>
                  {newCodes.length} código{newCodes.length !== 1 ? "s" : ""} registrado{newCodes.length !== 1 ? "s" : ""} esta sesión
                </div>
                <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
                  {newCodes.map((item, i) => (
                    <div key={i} style={{ background:"#1a1a1a", border:"1px solid #1a5c30",
                      borderRadius:8, padding:"10px 14px",
                      display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                      <span style={{ fontFamily:"monospace", fontSize:14, fontWeight:600, color:"#4ade80" }}>
                        {item.full}
                      </span>
                      <span style={{ fontSize:10, color:"#4ade80", background:"#0b1a0f",
                        border:"1px solid #1a5c30", padding:"2px 8px", borderRadius:4 }}>NUEVO</span>
                    </div>
                  ))}
                </div>
                <button onClick={() => {
                  navigator.clipboard?.writeText(newCodes.map(c=>c.full).join("\n"))
                    .then(() => showToast("✓ Copiado al portapapeles"));
                }} style={{ ...S.btn, marginTop:16, width:"100%" }}>
                  Copiar todos al portapapeles
                </button>
              </>
            }
          </div>
        )}
      </div>

      {toast && (
        <div style={{ position:"fixed", bottom:20, left:"50%", transform:"translateX(-50%)",
          background:"#222", color:"#e8e8e8", border:"1px solid #404040",
          padding:"9px 20px", borderRadius:8, fontSize:12,
          boxShadow:"0 4px 20px rgba(0,0,0,.6)", zIndex:1000, whiteSpace:"nowrap" }}>
          {toast}
        </div>
      )}
      <style>{`input::placeholder{color:#555} *{font-family:'Inter',sans-serif!important}`}</style>
    </div>
  );
}